import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const COOKIES_FILE = path.resolve(__dirname, '..', 'tapd_cookies.json');

const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

const browser = await chromium.launch({ headless: false, args: ['--no-sandbox'] });
const context = await browser.newContext();
await context.addCookies(cookies);
const page = await context.newPage();

await page.goto('https://www.tapd.cn/31253609/prong/stories/add', { waitUntil: 'networkidle', timeout: 30000 });

// Check if redirected to login
if (page.url().includes('login')) {
  console.log('LOGIN_REDIRECT');
  await browser.close();
  process.exit(1);
}

await page.waitForTimeout(3000);

// Get all form input/select/textarea fields and their IDs
const inputInfo = await page.evaluate(() => {
  const fields = document.querySelectorAll('input, select, textarea');
  const result = [];
  fields.forEach(el => {
    const tag = el.tagName.toLowerCase();
    const id = el.id || '(no id)';
    const name = el.name || '(no name)';
    const type = el.type || '';
    const label = el.labels?.[0]?.innerText?.trim() || '';
    result.push({ tag, id, name, type, label });
  });
  return result;
});

console.log('=== Form Fields ===');
inputInfo.forEach(f => console.log(JSON.stringify(f)));

// Get all iframes (for rich text editors)
const iframes = await page.evaluate(() => {
  return Array.from(document.querySelectorAll('iframe')).map(f => ({
    id: f.id,
    title: f.title,
    src: (f.src || '').substring(0, 200),
  }));
});
console.log('=== Iframes ===');
iframes.forEach(f => console.log(JSON.stringify(f)));

// Get all clickable elements that might be "模板" template selection
const links = await page.evaluate(() => {
  return Array.from(document.querySelectorAll('a, button, span[onclick], label')).slice(0, 100).map(el => ({
    tag: el.tagName.toLowerCase(),
    id: el.id || '',
    class: (el.className || '').substring(0, 100),
    text: (el.innerText || '').substring(0, 100),
    onclick: (el.getAttribute('onclick') || '').substring(0, 100),
  }));
});
console.log('=== Links/Buttons ===');
links.forEach(l => console.log(JSON.stringify(l)));

// Screenshot
await page.screenshot({ path: path.resolve(__dirname, '..', 'memory/tapd_story_page.png'), fullPage: true });

await browser.close();

