import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const COOKIES_FILE = path.resolve(__dirname, '..', 'tapd_cookies.json');

const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

const browser = await chromium.launch({ headless: false, args: ['--no-sandbox'] });
const context = await browser.newContext({ userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' });
await context.addCookies(cookies);
const page = await context.newPage();
await page.addInitScript(() => {
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
});

await page.goto('https://www.tapd.cn/31253609/prong/stories/add', { waitUntil: 'networkidle', timeout: 30000 });

if (page.url().includes('login')) {
  console.log('LOGIN_REDIRECT');
  await browser.close();
  process.exit(1);
}

await page.waitForTimeout(3000);

// Get dropdown fields and their options
const fields = await page.evaluate(() => {
  const selectors = ['#StoryPriority', '#StoryModule', '#StoryVersion', '#StoryCustomFieldOne', '#StoryCustomFieldTwo', '#StoryCustomFieldThree', '#StoryCurrentOwnerValue', '#StoryCcValue', 'input[name*="owner"]', 'input[name*="Priority"]', 'input[name*="Module"]', 'input[name*="Version"]', 'input[name*="Branch"]'];
  const result = [];
  for (const sel of selectors) {
    const el = document.querySelector(sel);
    if (el) {
      result.push({
        selector: sel,
        tag: el.tagName.toLowerCase(),
        id: el.id,
        name: el.name,
        type: el.type || el.tagName.toLowerCase(),
        class: (el.className || '').substring(0, 100),
      });
    } else {
      result.push({ selector: sel, found: false });
    }
  }
  return result;
});

console.log('=== Specific fields ===');
fields.forEach(f => console.log(JSON.stringify(f)));

// Also dump the form structure
const formHTML = await page.evaluate(() => {
  const storyForm = document.getElementById('story-form') || document.querySelector('form');
  if (!storyForm) return { error: 'no form found' };
  return {
    id: storyForm.id,
    action: storyForm.action,
    fields: Array.from(storyForm.querySelectorAll('input, select, textarea, div[contenteditable]')).map(el => ({
      tag: el.tagName.toLowerCase(),
      id: el.id || '',
      name: el.name || '',
      type: el.type || '',
      class: (el.className || '').substring(0, 80),
      placeholder: el.placeholder || '',
    }))
  };
});

console.log('\n=== Form Structure ===');
if (formHTML.error) console.log(formHTML.error);
else {
  formHTML.fields.forEach(f => console.log(JSON.stringify(f)));
}

// Get all select elements with their options
const selects = await page.evaluate(() => {
  return Array.from(document.querySelectorAll('select')).map(s => ({
    id: s.id,
    name: s.name,
    options: Array.from(s.options).map(o => ({ value: o.value, text: o.text })),
  }));
});
console.log('\n=== Select Options ===');
selects.forEach(s => {
  console.log(`\nSelect: ${s.id} (name: ${s.name})`);
  s.options.forEach(o => console.log(`  ${o.value}: ${o.text}`));
});

// Screenshot
await page.screenshot({ path: path.resolve(__dirname, '..', 'memory/tapd_story_page2.png'), fullPage: true });

await browser.close();

