import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const COOKIES_FILE = path.resolve(__dirname, '..', 'tapd_cookies.json');

const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

const browser = await chromium.launch({ headless: false, args: ['--no-sandbox'] });
const context = await browser.newContext({ userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' });
await context.addCookies(cookies);
const page = await context.newPage();
await page.addInitScript(() => {
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
});

await page.goto('https://www.tapd.cn/31253609/prong/stories/add', { waitUntil: 'networkidle', timeout: 30000 });

if (page.url().includes('login')) {
  console.log('LOGIN_REDIRECT');
  await browser.close();
  process.exit(1);
}

await page.waitForTimeout(3000);

// Click the template dropdown to see if more options load
const templateToggle = page.locator('.dropdown-toggle:has-text("系统默认模板1")').first();
const toggleCount = await templateToggle.count();
console.log(`Template toggle found: ${toggleCount}`);

if (toggleCount > 0) {
  await templateToggle.click();
  await page.waitForTimeout(2000);

  // Now look at what options appeared
  const templateOptions = await page.evaluate(() => {
    const items = document.querySelectorAll('.template-item__link, .dropdown-menu a, [class*="template"]');
    return Array.from(items).map(a => ({
      text: a.innerText?.trim()?.substring(0, 100),
      id: a.id,
      class: (a.className || '').substring(0, 80),
      dataValue: a.getAttribute('data-value'),
    }));
  });
  console.log('\n=== Template Dropdown Options ===');
  templateOptions.forEach(o => console.log(JSON.stringify(o)));
}

// Check if there's a way to manually add sub-workitems
