  // Look for the preset workitems panel
  const container = document.querySelector('[class*="workitems"], [class*="preset"], .tab-content, .add_workitem');
  // Check for "添加子工作项" or similar buttons
  const addBtns = Array.from(document.querySelectorAll('a, button')).filter(el => el.innerText.includes('添加') || el.innerText.includes('子工作') || el.innerText.includes('工作项'));
  return addBtns.map(b => ({ text: b.innerText, id: b.id, onclick: (b.getAttribute('onclick') || '').substring(0, 100), class: b.className }));
});
console.log('\n=== Workitem Add Buttons ===');
workitemInfo.forEach(w => console.log(JSON.stringify(w)));

// Also click clickable elements to see if there are more template presets
const allTemplates = await page.evaluate(() => {
  const selects = document.querySelectorAll('select');
  const templateSelect = Array.from(selects).find(s => s.id === 'TemplateId');
  if (templateSelect) {
    return Array.from(templateSelect.options).map(o => ({ value: o.value, text: o.text }));
  }
  return [];
});
console.log('\n=== All Available Templates ===');
allTemplates.forEach(t => console.log(JSON.stringify(t)));

await browser.close();

