import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const COOKIES_FILE = path.resolve(__dirname, '..', 'tapd_cookies.json');

const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

const browser = await chromium.launch({ headless: false, args: ['--no-sandbox'] });
const context = await browser.newContext({ userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' });
await context.addCookies(cookies);
const page = await context.newPage();
await page.addInitScript(() => {
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
});

await page.goto('https://www.tapd.cn/31253609/prong/stories/add', { waitUntil: 'networkidle', timeout: 30000 });

if (page.url().includes('login')) {
  console.log('LOGIN_REDIRECT');
  await browser.close();
  process.exit(1);
}

await page.waitForTimeout(3000);

// Find the title input, template dropdown, owner handling, submit button
const details = await page.evaluate(() => {
  // Title - look for any visible text input that's not hidden
  const allInputs = Array.from(document.querySelectorAll('input[type="text"]'));
  const visibleInputs = allInputs.filter(i => i.offsetParent !== null || !i.hidden);

  const titleInputs = visibleInputs.filter(i => {
    const label = i.closest('.control-group')?.querySelector('.control-label')?.innerText || '';
    return label.includes('标题') || label.includes('Title') || i.id.includes('Title') || i.name.includes('title') || i.name.includes('Title') || i.id.includes('story_name') || i.placeholder?.includes('标题');
  });

  // Template dropdown
  const templateSelect = document.getElementById('TemplateId');
  const templateOptions = templateSelect ? Array.from(templateSelect.options).map(o => ({ value: o.value, text: o.text })) : [];

  // All visible text inputs and their context
  const allVisibleInputs = allInputs.map(i => {
    const label = i.closest('.control-group')?.querySelector('.control-label')?.innerText || '';
    const parentHtml = i.closest('.control-group')?.innerHTML?.substring(0, 300) || '';
    return {
      id: i.id,
      name: i.name,
      placeholder: i.placeholder,
      type: i.type,
      visible: i.offsetParent !== null,
      label: label
    };
  });

  return {
    titleInputs: titleInputs.map(i => ({ id: i.id, name: i.name, placeholder: i.placeholder })),
    templateOptions,
    allVisibleInputs,
    pageUrl: window.location.href,
    storyName: document.getElementById('StoryName')?.outerHTML || 'no #StoryName',
    storyTitle: document.getElementById('StoryTitle')?.outerHTML || 'no #StoryTitle',
  };
});

console.log('=== Title Inputs ===');
console.log(JSON.stringify(details.titleInputs, null, 2));
console.log('\n=== Template Options ===');
console.log(JSON.stringify(details.templateOptions, null, 2));
console.log('\n=== StoryName/Title elements ===');
console.log(details.storyName);
console.log(details.storyTitle);
console.log('\n=== Visible Text Inputs (sample) ===');
details.allVisibleInputs.filter(i => i.visible).slice(0, 20).forEach(i => console.log(JSON.stringify(i)));

// Look for the submit button
const submitBtn = await page.evaluate(() => {
  const btns = Array.from(document.querySelectorAll('a, button, input[type="submit"]'));
  return btns.filter(b => b.innerText?.includes('创建') || b.value?.includes('创建') || b.id?.includes('story_submit') || b.id?.includes('save')).map(b => ({
    tag: b.tagName.toLowerCase(), id: b.id, text: b.innerText || b.value, onclick: (b.getAttribute('onclick') || '').substring(0, 100)
  }));
});
console.log('\n=== Submit Buttons ===');
submitBtn.forEach(b => console.log(JSON.stringify(b)));

// Also check what autocomplete mechanism is used for owner
const ownerHTML = await page.evaluate(() => {
  const ownerGroup = document.querySelector('[class*="owner"]')?.closest('.control-group') || document.querySelector('[id*="owner"]')?.closest('.control-group');
  return ownerGroup ? ownerGroup.innerHTML.substring(0, 1000) : 'no owner group found';
});
console.log('\n=== Owner Section HTML ===');
console.log(ownerHTML);

// CC section
const ccHTML = await page.evaluate(() => {
  const ccGroup = document.querySelector('[id*="CcValue"]')?.closest('.control-group') || document.querySelector('[id*="cc"]')?.closest('.control-group');
  return ccGroup ? ccGroup.innerHTML.substring(0, 1000) : 'no cc group found';
});
console.log('\n=== CC Section HTML ===');
console.log(ccHTML);

await page.screenshot({ path: path.resolve(__dirname, '..', 'memory/tapd_story_form.png'), fullPage: true });

await browser.close();

