  console.log('LOGIN_REDIRECT');
  await browser.close();
  process.exit(1);
}

await page.waitForTimeout(3000);

// Check all presets info
const presetInfo = await page.evaluate(() => {
  const presets = document.querySelectorAll('input[name*="PresetItems"]');
  const result = {};
  presets.forEach(input => {
    const name = input.name;
    const match = name.match(/data\[PresetItems\]\[(\d+)\]\[(\w+)\]/);
    if (match) {
      const idx = match[1];
      const field = match[2];
      if (!result[idx]) result[idx] = {};
      result[idx][field] = input.value;
    }
  });
  return result;
});

console.log('=== Preset Items ===');
Object.entries(presetInfo).forEach(([key, val]) => {
  console.log(`\n[${key}]:`, JSON.stringify(val));
});

