  if (container) return container.innerHTML.substring(0, 2000);
  // Look for checkboxes in the template-related area
  const labels = document.querySelectorAll('label.checkbox');
  const presetCheckboxes = Array.from(labels).filter(l => l.innerText.includes('客户端') || l.innerText.includes('QA') || l.innerText.includes('策划'));
  return presetCheckboxes.length > 0 ? presetCheckboxes.map(l => l.innerHTML).join('\n') : 'no preset checkboxes found';
});
console.log('\n=== Preset/Checkbox Area ===');
console.log(presetHTML);

await browser.close();

