import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WS_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WS_DIR, 'tapd_cookies.json');
const WORKSPACE_ID = '31253609';
const STORY_CREATE_URL = `https://www.tapd.cn/${WORKSPACE_ID}/prong/stories/add`;

const STEALTH_SCRIPT = `
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
  Object.defineProperty(navigator, 'plugins', { get: () => [1, 2, 3, 4, 5] });
  Object.defineProperty(navigator, 'languages', { get: () => ['zh-CN', 'zh', 'en'] });
  Object.defineProperty(navigator, 'hardwareConcurrency', { get: () => 8 });
  window.chrome = { runtime: {} };
`;

/**
 * Create a Story (需求) on TAPD
 */
export async function createStory(opts = {}) {
  const {
    title = '测试需求单 - 请忽略',
    priority = 'P2',
    module: mod = '1V1',
    version = '【1V1】正式版本V2.0',
    branch = 'YZY_1V1 V1.0 Beta',
    handler = '周以天',
    cc = '周以天',
    templateText = '客户端',
    description = '',
  } = opts;

  if (!title) throw new Error('title is required');

  if (!fs.existsSync(COOKIES_FILE)) {
    throw new Error(`Cookies file not found: ${COOKIES_FILE}`);
  }
  const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

  const browser = await chromium.launch({
    headless: false,
    args: [
      '--no-sandbox',
      '--disable-blink-features=AutomationControlled',
      '--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
    ],
  });

  const context = await browser.newContext({
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  });

  await context.addInitScript(STEALTH_SCRIPT);
  await context.addCookies(cookies);

  const page = await context.newPage();

  try {
    console.log('Opening story create page...');
    await page.goto(STORY_CREATE_URL, { waitUntil: 'networkidle', timeout: 30000 });

    if (page.url().includes('login')) {
      throw new Error('TAPD session expired, please re-login');
    }

    await page.waitForTimeout(2000);

    // ===== Select Template =====
    console.log('Selecting template: 客户端...');
    // Click the template dropdown toggle
    const templateToggle = page.locator('.dropdown-toggle').filter({ hasText: '系统默认模板1' }).first();
    await templateToggle.click();
    await page.waitForTimeout(1000);

    // Find and click "客户端" in the template list
    // The template items have class "template-item" and contain the text "客户端"
    const clientTemplate = page.locator('.template-item').filter({ hasText: '客户端' }).first();
    const clientTemplateCount = await clientTemplate.count();
    console.log(`Client template element found: ${clientTemplateCount}`);

    if (clientTemplateCount > 0) {
      // Get the <a> link inside the template item
      const clientTemplateLink = clientTemplate.locator('a').first();
      await clientTemplateLink.click();
      await page.waitForTimeout(2000);
      console.log('Client template selected');
    } else {
      console.warn('Client template not found, using default');
    }

    // ===== Fill Title =====
    await page.fill('#StoryName', title);
    console.log(`Title: ${title}`);

    // ===== Priority =====
    await page.selectOption('#StoryPriority', priority);
    console.log(`Priority: ${priority}`);

    // ===== Module =====
    await page.selectOption('#StoryModule', { label: mod });
    console.log(`Module: ${mod}`);

    // ===== Version =====
    await page.selectOption('#StoryVersion', { label: version });
    console.log(`Version: ${version}`);

    // ===== Branch (custom_field_one) =====
    try {
      // The branch field is an autocomplete input
      const branchInput = page.locator('#StoryCustomFieldOneValue').first();
      await branchInput.click();
      await branchInput.fill(branch);
      await page.waitForTimeout(1000);
      // Try pressing Enter to confirm autocomplete
      await page.keyboard.press('Enter');
      await page.waitForTimeout(500);
      console.log(`Branch: ${branch}`);
    } catch (e) {
      console.warn('Branch field not found/interactable:', e.message);
    }

    // ===== Owner (Handler) =====
    const ownerInput = page.locator('#StoryOwnerValue').first();
    await ownerInput.click();
    await ownerInput.type(handler, { delay: 100 });
    await page.waitForTimeout(2000); // Wait for autocomplete dropdown
    await page.keyboard.press('Enter');
    await page.waitForTimeout(600);
    console.log(`Handler: ${handler}`);

    // ===== CC =====
    const ccInput = page.locator('#StoryCcValue').first();
    await ccInput.click();
    await ccInput.type(cc, { delay: 100 });
    await page.waitForTimeout(2000);
    await page.keyboard.press('Enter');
    await page.waitForTimeout(600);
    console.log(`CC: ${cc}`);

    // ===== Description =====
    if (description) {
      try {
        const descFrame = page.frameLocator('iframe#StoryDescription_ifr').first();
        await descFrame.locator('body').fill(description);
        console.log('Description filled');
      } catch (e) {
        console.warn('Description field not found:', e.message);
      }
    }

    // Screenshot before submit
    await page.screenshot({ path: path.join(WS_DIR, 'memory/tapd_story_before_submit.png') });
    console.log('Screenshot saved');

    // ===== Submit =====
    console.log('Submitting story...');
    await page.locator('#btn_save_view').click();

    // Wait for navigation or success
    try {
      await page.waitForNavigation({ waitUntil: 'networkidle', timeout: 20000 });
    } catch {
      await page.waitForTimeout(5000);
    }

    const finalUrl = page.url();
    console.log(`Story created: ${finalUrl}`);
    return finalUrl;

  } finally {
    await browser.close();
  }
}

// Command line entry
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const args = process.argv.slice(2);
  const title = args[0] || '测试需求单 - 请忽略';
  createStory({ title })
    .then(url => {
      console.log('SUCCESS:', url);
      process.exit(0);
    })
    .catch(err => {
      console.error('FAILED:', err.message);
      process.exit(1);
    });
}

