const browser = await chromium.launch({ headless: false, args: ['--no-sandbox'] });
const context = await browser.newContext({ userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' });
await context.addCookies(cookies);
const page = await context.newPage();
await page.addInitScript(() => {
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
});

await page.goto('https://www.tapd.cn/31253609/prong/stories/add', { waitUntil: 'networkidle', timeout: 30000 });

if (page.url().includes('login')) {
  console.log('LOGIN_REDIRECT');
  await browser.close();
  process.exit(1);
}

await page.waitForTimeout(3000);

// Check all presets info
const presetInfo = await page.evaluate(() => {
  const presets = document.querySelectorAll('input[name*="PresetItems"]');
  const result = {};
  presets.forEach(input => {
    const name = input.name;
    const match = name.match(/data\[PresetItems\]\[(\d+)\]\[(\w+)\]/);
    if (match) {
      const idx = match[1];
      const field = match[2];
      if (!result[idx]) result[idx] = {};
      result[idx][field] = input.value;
    }
  });
  return result;
});

console.log('=== Preset Items ===');
Object.entries(presetInfo).forEach(([key, val]) => {
  console.log(`\n[${key}]:`, JSON.stringify(val));
});

// Also check the template system
const templateInfo = await page.evaluate(() => {
  // Find the template dropdown trigger
  const templateDropdown = document.querySelector('.dropdown-toggle')?.closest('.dropdown');
  if (!templateDropdown) return { noDropdown: true };

  const templateLinks = templateDropdown.querySelectorAll('a');
  return Array.from(templateLinks).map(a => ({
    text: a.innerText?.trim()?.substring(0, 100),
    id: a.id,
    href: a.href,
    dataValue: a.getAttribute('data-value'),
    onclick: a.getAttribute('onclick')?.substring(0, 100),
  }));
});

console.log('\n=== Template System ===');
console.log(JSON.stringify(templateInfo, null, 2));

// Check form action
const formAction = await page.evaluate(() => {
  const form = document.querySelector('form');
